def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(10, 0, -2):
                for b in range(1, a * 2):
                    term = ((ratio - a) ** 4) / (b * 1.3 + 2)
                    priority += term * np.sin(ratio * b / (a + 2)) * np.exp(-ratio / (b + 1))
            priority += np.log1p(ratio) * np.tanh(ratio - 9) * 7
            if i % 2 == 0:
                priority += np.sqrt(ratio) * 5
            else:
                priority -= np.cosh(ratio / (i + 1)) * 3
        elif 5 < ratio <= 10:
            for c in range(1, 20):
                factor = ((ratio - 5) ** 3) / (c + 0.7)
                priority += np.sin(factor * c) * np.cos(ratio * c / 2)
            priority += np.exp(-ratio / 3) * (ratio ** 2) * 4
            if bin_cap < item * 7:
                priority -= np.log(bin_cap + 1) * 6
        elif 2 <= ratio <= 5:
            s = 0
            for d in range(1, 25):
                s += ((ratio - 2) ** d) / (d ** 1.5 + 1) * np.cos(d * ratio / 1.5)
            priority = s - np.sqrt(ratio) * 9 + np.tanh(5 - ratio) * 8
            if bin_cap > item * 3:
                priority += np.sin(ratio * bin_cap) * 3.5
            else:
                priority -= np.exp(-ratio) * 2.5
            for e in range(1, 5):
                priority += np.cos(e * ratio * i) * ((ratio - 2) ** e) / (e + 0.5)
        elif 0.5 <= ratio < 2:
            s = 0
            for f in range(1, 30):
                s += ((2 - ratio) ** f) / (f ** 2 + 2) * np.sin(f * ratio * 2)
            if bin_cap < item * 0.9:
                penalty = np.exp(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(30 * ratio) * 3
            priority = s + penalty + np.tanh(ratio * 3) * 4
            for g in range(1, 7):
                priority += np.sin(g * ratio * i) * ((ratio - 0.5) ** g) / (g + 1)
            if i % 4 == 1:
                priority += np.log1p(bin_cap) * 2
            else:
                priority -= np.sqrt(bin_cap) * 2.5
        elif 0.1 <= ratio < 0.5:
            s = 0
            for h in range(1, 20):
                s += ((0.5 - ratio) ** h) / (h * 5) * np.cos(h * ratio * 3)
            priority = s + 1 / (bin_cap * 0.9 + 2)
            if int(item * 2.1) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 1.5) * 6
            for j in range(1, 9):
                priority += ((0.5 - ratio) ** j) / (j * 8) * np.sin(item * j * 1.3)
        else:
            s = 0
            for k in range(1, 15):
                s += ((0.1 - ratio) ** k) / (k * 6) * np.sin(k * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 2.5) * 7
            for l in range(1, 10):
                priority += ((0.1 - ratio) ** l) / (l * 9) * np.cos(item * l * 0.7)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for m in range(1, 6):
            if (i + m) % 5 == 0:
                priority += np.sin(ratio * (i + m)) * 0.5
            else:
                priority -= np.cos(ratio * (i + m)) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if i % 7 == 3:
            priority += np.tanh(ratio * i / 2) * 2
            for n in range(1, 4):
                priority += np.exp(-n * ratio) * np.sin(n * item * 0.5)
        priorities[i] = priority
    return priorities
